#include <iostream>
using namespace std;
long long t, n, a[1005], mini;
int main()
{
	cin >> t;
	a[0] = 9e18;
	while (t--)
	{
		cin >> n;
		mini = 0;
		for (int i = 1;i <= n;i++)
		{
			cin >> a[i];
			if (a[i] < a[mini])
			{
				mini = i;
			}
		}
		if (n % 2)
		{
			cout << "Jerry\n";
		}
		else
		{
			cout << (mini % 2 ? "Tom\n" : "Jerry\n");
		}
	}
	return 0;
}
